// UART Transmitter - 9600 baud
module RefModule(
  input [2:0] binary_in,
  output reg [7:0] binary_out
);always @ (binary_in)
    case(binary_in)
      3'b000: binary_out = 8'b00000001;
      3'b001: binary_out = 8'b00000010;
      3'b010: binary_out = 8'b00000100;
      3'b011: binary_out = 8'b00001000;
      3'b100: binary_out = 8'b00010000;
      3'b101: binary_out = 8'b00100000;
      3'b110: binary_out = 8'b01000000;
      3'b111: binary_out = 8'b10000000;
    endcase

endmodule
